import * as t from "io-ts";
import { UnstakeIntent } from "./unstakeIntent";
import { NonEmptyString } from "io-ts-types";
import { UndelegateIntent } from "./undelegateIntent";

/**
 * @title Common VET unstake intent fields
 *
 *
 * @param {string} tokenId - The ID of the NFT token
 * @param {string} stakingContractAddress - The address of the stargate contract
 */
const VetUnstakeCommonFields = t.type({
  tokenId: NonEmptyString,
  stakingContractAddress: NonEmptyString,
});

/**
 * @title VET Exit Delegation Intent
 *
 * Intent for the first step of VET unstaking process - exiting delegation
 * This calls the exitDelegation function on the stargate contract
 */
export const VetExitDelegationIntent = t.intersection([
  UndelegateIntent,
  VetUnstakeCommonFields,
]);

export type VetExitDelegationIntent = t.TypeOf<typeof VetExitDelegationIntent>;

/**
 * @title VET Burn NFT Intent
 *
 * Intent for the second step of VET unstaking process - burning the NFT
 * This calls the burn function on the stargate contract after the cooldown period
 */
export const VetBurnNFTIntent = t.intersection([
  UnstakeIntent,
  VetUnstakeCommonFields,
]);

export type VetBurnNFTIntent = t.TypeOf<typeof VetBurnNFTIntent>;
